def bellman_ford(G, N, S):

    res = [INF for _ in range(N)]
    res[S] = 0
    for _ in range(N-1):
        for i in range(N):
            if res[i] == INF:
                continue
            for sa, sb in G[i]:
                res[sa] = min(res[sa], res[i]+sb)
    for i in range(N):
        if res[i] == INF:
            continue
        for sa, sb in G[i]:
            if res[sa] > res[i]+sb:
                return False
    return res

