def binSearch(lst, x):
	m = [10**12]*2
	high = len(lst) - 1
	low = 0
	dst = 10**12

	while low <= high:
		mid = (low+high)//2
		if lst[mid] < x:
			if x - lst[mid] < dst:
				m[0] = lst[mid]
				dst = x - lst[mid]
			elif x - lst[mid] == dst:
				m[1] = lst[mid]
			low = mid + 1
		elif lst[mid] > x:
			if lst[mid] - x < dst:
				m[0] = lst[mid]
				dst = lst[mid] - x
			elif lst[mid] - x == dst:
				m[1] = lst[mid]
			high = mid - 1
	return m

def calculate(n, k, d, memo):
    if (n, d) in memo:
        return memo[(n, d)]
    else:
        if (n, d) == (0, 0):
            return 1
        x = 0
        if d == 0:
            i = 1
            while n - i >= 0 and i <= k:
                x += calculate(n-i, k, 0, memo)
                i += 1
        else:
            for i in range(1, k+1):
                if i >= d:
                    x += calculate(n-i, k, 0, memo)
                elif n >= i + d:
                    x += calculate(n-i, k, d, memo)
        memo[(n, d)] = x
        return x

def query(self, start, stop):
        if start == stop:
            return self.__getitem__(start)
        stop += 1
        start += self._size
        stop += self._size

        res = self._default
        while start < stop:
            if start & 1:
                res = self._func(res, self.data[start])
                start += 1
            if stop & 1:
                stop -= 1
                res = self._func(res, self.data[stop])
            start >>= 1
            stop >>= 1
        return res

