def bin_search(k, f):
    for d in range(1,20):
        if f(10**(d-1)-1) > k:
            break
    upper = 10**(d-1)-1
    lower = 10**(d-2)-1
    while upper-lower > 1:
        middle = (lower+upper)//2;
        if f(middle) > k:
            upper = middle
        else:
            lower = middle
    return lower, k-f(lower)

