def query(n, sega, l, r):
    l += n
    r += n
    res = -1
    while l < r:
        if l & 1 == 1:
            if res == -1:
                res = sega[l]
            else:
                res = gcd(res, sega[l])
            l += 1
        if r & 1 == 1:
            r -= 1
            if res == -1:
                res = sega[r]
            else:
                res = gcd(res, sega[r])

        l //= 2
        r //= 2
    return res

