      return True,0

  if x>arr[-1]:
    return False,len(arr)
  elif x<arr[0]:
    return False,-1

  beg,end=0,len(arr)-1
  while beg<=end:
    mid=(beg+end)//2
    if arr[mid]==x:
      return True,mid
    elif x>arr[mid]:
      if x<arr[mid+1]:
        return False,mid+1
      else:
        beg=mid+1
    else:
      if x>arr[mid-1]:
        return False,mid-1
      else:
        end=mid-1

def array_partition(n, a_a):
    lm = [a_a[0]]
    rm = [a_a[-1]]

    for i in range(1, n):
        lm.append(max(lm[-1], a_a[i]))
        rm.append(max(rm[-1], a_a[-(i+1)]))

    r = n - 1
    for l in range(n - 2):
        left = lm[l]
        while r > l + 1 and rm[n - 1 - r] <= left:
            r -= 1
        if r < n - 1:
            r += 1

        if left == rm[n - 1 - r]:
            mm = query(0, 0, n - 1, l + 1, r - 1)
            if left == mm:
                return [l + 1, r - l - 1, n - r]
            elif mm < left:
                pass
            elif r < n - 1:
                r += 1
                if left == rm[n - 1 - r] and query(0, 0, n - 1, l + 1, r - 1) == left:
                    return [l + 1, r - l - 1, n - r]
    return []

