def solve(nums, odd):
    changes = 0
    last_odd = next_odd(nums, -1)
    last_even = next_even(nums, -1)

    for x in range(len(nums)):
        if odd and nums[x] % 2 == 0:
            if last_odd == len(nums):
                return float('inf')
            nums[x], nums[last_odd] = nums[last_odd], nums[x]
            changes += abs(last_odd - x)
            last_odd = next_odd(nums, last_odd)
        if not odd and nums[x] % 2 == 1:
            if last_even == len(nums):
                return float('inf')
            nums[x], nums[last_even] = nums[last_even], nums[x]
            changes += abs(last_even - x)
            last_even = next_even(nums, last_even)

        if x >= last_even:
            last_even = next_even(nums, last_even)
        if x >= last_odd:
            last_odd = next_odd(nums, last_odd)

        odd = not odd

    return changes

