def find(stack,m,count=1,visited={}):
    l = len(stack)
    tmp = []
    for e in stack:
        l = e*2
        r = e-1
        if l < 2*m:
            if l not in visited:
                tmp += [l]
                visited[l] = 0
        if r > 0:
            if r not in visited:
                tmp += [r]
                visited[r] = 0

    stack=tmp
    if m in visited:
        return count
    else:
        return find(stack,m,count+1)

