def merge_sort(l):
    def merge(l1, l2):
        i, j = 0, 0
        output_list = []
        while i < len(l1) and j < len(l2):
            if l1[i][0] < l2[j][0]:
                output_list.append(l1[i])
                i += 1
            else:
                output_list.append(l2[j])
                j += 1
        if i == len(l1):
            output_list += (l2[j:])
        else:
            output_list += (l1[i:])
        return output_list

    def sorts(l):
        if len(l) < 2:
            return l
        else:
            mid = len(l) // 2
            left = sorts(l[:mid])
            right = sorts(l[mid:])
            return merge(left, right)
    return sorts(l)

