def levenshtein_distance(x, y):
    lx = len(x); ly = len(y)
    dp = [[0 for i in range(ly + 1)] for j in range(lx + 1)]

    for i in range(lx + 1):
        dp[i][0] = i
    for j in range(1, ly + 1):
        dp[0][j] = j

    for i in range(1, lx + 1):
        for j in range(1, ly + 1):
            if x[i - 1] == y[j - 1]:
                cost = 0
            else:
                cost = 1

            dp[i ][j] = min(dp[i - 1][j] + 1, dp[i][j - 1] + 1, dp[i - 1][j - 1] + cost)

    return dp[lx][ly]

