def sf(S, C, C0):
    if C0 == '0':
        return True

    if S[0] == '0':
        return False

    def g1():
        yield from S
        for _ in range(C['0']):
            yield '0'
        for _ in range(C[C0]):
            yield C0

    def g2():
        yield C0
        for _ in range(C['0']):
            yield '0'
        for _ in range(C[C0] - 1):
            yield C0
        yield from S


    for d1, d2 in zip(g1(), g2()):
        if d1 < d2:
            return True
        elif d1 > d2:
            return False

    return True

