def compress(songs, m):
    ucsum = 0
    ccsum = 0
    for k in songs:
        ucsum += k.uc
        ccsum += k.c
    if ccsum > m:
        return -1

    if ucsum <= m:
        return 0
    diff = []
    for k in songs:
        diff.append(k.uc - k.c)

    diff.sort(reverse = True)

    for j in range(len(diff)):
        if ucsum <= m:
            return j
        else:
            ucsum -= diff[j]
    if ucsum <= m:
        return len(songs)

