def solve(a, n):
    a = sorted(a)
    count = {}
    for i in range(n):
        count[a[i]] = count.get(a[i], 0) + 1 
    temp = sorted(list(set(a)))

    dp = [i for i in temp]
    dp[0] = count[temp[0]]*temp[0]
    if len(temp) == 1:
        return dp[0]
    if temp[1] == temp[0] + 1:
        dp[1] = max(count[temp[1]] * temp[1], dp[0])
    else:
        dp[1] = dp[0] + count[temp[1]] * temp[1]

    for i in range(2, len(temp)):
        if temp[i] == temp[i - 1] + 1:
            dp[i] = max(count[temp[i]] * temp[i] + dp[i - 2], dp[i - 1])
        else:
            dp[i] = dp[i - 1] + count[temp[i]] * temp[i]
    return dp[-1]

def findMaxN(x, left=0, right=26000):
    while left < right:
        mid = (left + right) // 2
        a = num(mid)
        b = num(mid+1)
        c = num(mid-1)
        if(b > x and a < x):
            return mid
        elif(a > x and c < x):
            return mid - 1
        elif(a == x):
            return mid
        elif a < x:
            left = mid + 1
        elif a > x:
            right = mid - 1

    return right

