def solve(n, xs):
    if n <= 5:
        return IMP

    half = n // 2
    i = half
    while i > 0 and xs[i] == xs[i - 1]:
        i -= 1

    if i == 0 and xs[i] == xs[i + 1]:

        return IMP


    ys = [(x, len(list(b))) for x, b in groupby(xs[:i])]



    if len(ys) < 3:
        return IMP





    g = ys[0][1]
    if 3 * g > half - 2:
        return IMP


    s = 0
    ind = 1
    while s <= g and ind < len(ys):
        s += ys[ind][1]
        ind += 1

    if s < g:
        return IMP

    b = sum(y[1] for y in ys[ind:])
    if b <= g:
        return IMP

    return " ".join(map(str, (g, s, b)))

