def get_shortest_path(floors, current, closed_foors, closed):
    if current not in closed_floors:
        return 0

    highers = set(i + current for i in range(0, closed + 1))
    lowers = set(current - i for i in range(closed, 0, -1))

    lower_h, lower_s = 10000000000, -10000000000

    for i in highers:
        if i < lower_h and i <= floors and i not in closed_floors:
            lower_h =  i

    for i in lowers:
        if i > lower_s  and i > 0 and i not in closed_floors:
            lower_s = i


    lower_h = abs(abs(lower_h) - current)
    lower_s = abs(abs(lower_s) - current)

    return lower_h if lower_h < lower_s else lower_s

