def solve(r1, c1, r2, c2, n, nav_mat):
    visited = [[0] * n for _ in range(n)]
    components = []

    for r in range(n):
        for c in range(n):
            if nav_mat[r][c] or visited[r][c]:
                continue

            visited[r][c] = 1
            dq = deque([(r,c)])
            component = set()
            while dq:
                cr, cc = dq.popleft()
                component.add((cr, cc))

                for dr, dc in ((cr+1, cc), (cr-1,cc), (cr, cc+1), (cr, cc-1)):
                    if 0 <= dr < n and 0 <= dc < n and not nav_mat[dr][dc] and not visited[dr][dc]:
                        visited[dr][dc] = 1
                        dq.append((dr, dc))

            components.append(component)

    for i in range(len(components)):
        if (r1, c1) in components[i]:
            start_component = i
        if (r2, c2) in components[i]:
            end_component = i

    if start_component == end_component:
        return 0

    best = float("inf")
    for r1, c1 in components[start_component]:
        for r2, c2 in components[end_component]:
            best = min(best, (r1-r2)**2 + (c1-c2)**2)

    return best

