def find_perim(x, y, n):
	curr_area = x * y
	if curr_area == n or curr_area - x < n or curr_area - y < n:
		return 2 * x + 2 * y
	elif curr_area - x >= n:
		return find_perim(x - 1, y, n)
	elif curr_area - y >= n:
		return find_perim(x, y - 1, n)
	else:
		for i in range(n):
			curr_area -= i
			if curr_area == n:
				return 2 * x + 2 * y
			elif curr_area < n:
				break
		return -1

