def burger(recipe,quantity,price,coins):
    cb=recipe.count("B")
    cs=recipe.count("S")
    cc=recipe.count("C")
    if cb==0:
        quantity[0]=0
    if cs==0:
        quantity[1]=0
    if cc==0:
        quantity[2]=0
    ans=0
    while True:
        if quantity[0]>=cb and quantity[1]>=cs and quantity[2]>=cc:
            quantity[0]-=cb
            quantity[1]-=cs
            quantity[2]-=cc
            ans+=1
        else:
            break
    while coins>0 and quantity.count(0)!=3:
        if quantity[0]>=cb:
            quantity[0]-=cb
        else:
            coins-=(cb-quantity[0])*price[0]
            quantity[0]=0
        if quantity[1]>=cs:
            quantity[1]-=cs
        else:
            coins-=(cs-quantity[1])*price[1]
            quantity[1]=0
        if quantity[2]>=cc:
            quantity[2]-=cc
        else:
            coins-=(cc-quantity[2])*price[2]
            quantity[2]=0
        if coins>=0:
            ans+=1
    if coins<0:
        coins=0
    cost=cb*price[0]+cs*price[1]+cc*price[2]
    ans+=coins//cost
    return ans

