def path_heap_Dijkstra(self, root):

        self.distance[root] = 0
        path_heap = list()

        hp.heappush(path_heap, (0, root))

        while path_heap:
            current = hp.heappop(path_heap)[1]
            self.visited[current] = BLACK

            for adj, cost in self.adj_table[current].items():
                if self.visited[adj] is not BLACK:

                    alt_path = self.distance[current] + cost
                    if alt_path < self.distance[adj]:

                        self.distance[adj] = alt_path

                        hp.heappush(path_heap, (alt_path, adj))
                        self.visited[adj] = GRAY
                        self.parent[adj] = current

        return self.distance

