def cargo(sizes):
    limit = 4
    count_taxi = 0
    count_unique = col.Counter(sizes)
    unique = sorted(count_unique.keys(), reverse=True)
    class OutLoop(Exception): pass
    while sum(count_unique.values()) > 0:
        try:
            capas = 0
            for u in unique:
                while count_unique[u] > 0 and capas + u <= limit:
                    capas += u
                    count_unique[u] -= 1
                    if capas == limit:
                        count_taxi += 1
                        raise OutLoop()
            else:
                if capas > 0:
                    count_taxi += 1

        except OutLoop:
            pass
    return count_taxi

