def AliceScore(nums):
	score = 0
	alice_turn = True

	while '1' in nums:
		longest = -1
		start_idx = -1
		i = 0
		while i < len(nums):
			if nums[i] == '1':
				streak = 0
				while i < len(nums) and nums[i] == '1':
					i += 1
					streak += 1
				if streak > longest:
					longest = streak
					start_idx = i - streak
			else:
				i += 1
		if alice_turn:
			score += longest
		alice_turn = not alice_turn
		nums = nums[:start_idx] + nums[start_idx + longest:]
	return score

