def cut_with_constraints(n_val: int, a_val: int, b_val: int, c_val: int) -> int:

    candidates = []
    max_cut = 0
    for a_times_x in range(0, n_val+1, a_val):
        for b_times_y in range(0, n_val+1-a_times_x, b_val):
            c_times_z = n_val - a_times_x - b_times_y
            if c_times_z % c_val == 0:
                z = c_times_z // c_val
                x_plus_y_plus_z = a_times_x // a_val + b_times_y // b_val + z

