def divide(n):
        def generator(n):
            divisors = []
            for i in range(1, int(n**(1/2))+1):
                if n%i == 0:
                    yield i
                    if i*i != n:
                        divisors.append(n/i)
            for divisor in reversed(divisors):
                yield int(divisor)
        return list(generator(n))[1:-1]

