def dijkstra_path_heap():

    distance[init_vertex] = 0
    path_heap = []

    hp.heappush(path_heap, (0, init_vertex))

    while path_heap:
        current_vertex = hp.heappop(path_heap)[1]

        color[current_vertex] = BLACK

        for adj_vertex, adj_weight in adj_table[current_vertex].items():
            if color[adj_vertex] is not BLACK:

                alt_path = distance[current_vertex] + adj_weight
                if alt_path < distance[adj_vertex]:

                    distance[adj_vertex] = alt_path

                    hp.heappush(path_heap, (alt_path, adj_vertex))
                    color[adj_vertex] = GRAY

    return distance

