def solve():
	class st:
		def __init__(self, n):
			self.ntrl = float('inf')
			h = int(math.log2(n-1))+1 if n>1 else 0
			N = 2**h
			self.t = [self.ntrl]*(2*N)
			self.d = [0]*N
			self.N = N
			self.h = h

		def merge(self,a,b):
			return min(a,b)


		def apply(self, p, value):
			self.t[p] += value
			if (p < self.N):
				self.d[p] += value

		def build(self, p):
			t = self.t
			d = self.d
			while p > 1:
				p >>= 1
				t[p] = self.merge(t[p<<1], t[p<<1|1]) + d[p]

		def rebuild(self):
			t = self.t
			for p in reversed(range(1, self.N)):
				t[p] = self.merge(t[p<<1], t[p<<1|1])

		def push(self, p):
			d = self.d
			for s in range(self.h, 0, -1):
				i = p >> s
				if d[i] != 0:
					self.apply(i<<1, d[i])
					self.apply(i<<1|1, d[i])
					d[i] = 0

		def inc(self, l, r, value):
			if l > r:
				return

			l += self.N
			r += self.N+1
			l0, r0 = l, r
			while l < r:
				if l & 1:
					self.apply(l, value)
					l += 1
				if r & 1:
					r -= 1
					self.apply(r, value)
				l >>= 1
				r >>= 1
			self.build(l0)
			self.build(r0 - 1)

		def query(self, l, r):
			if l > r:
				return self.ntrl
			t = self.t
			l += self.N
			r += self.N+1
			self.push(l)
			self.push(r - 1)
			res = self.ntrl
			while l < r:
				if l & 1:
					res = self.merge(res, t[l])
					l += 1
				if r & 1:
					r -= 1
					res = self.merge(t[r], res)
				l >>= 1
				r >>= 1
			return res

