def maxDiff(p, n):
    if n == 1:
        return 0
    used = {i for i in p}
    rest = {0:0, 1:0}
    for i in range(1, n+1):
        if i not in used:
            rest[i%2] += 1
    A00 = []
    A11 = []
    A01 = 0
    prev = -1
    start = -1
    for i, el in enumerate(p):
        if el == 0 and prev > 0:
            le = i
            start = prev
        elif el > 0 and prev == 0 and start > 0:
            start %= 2
            end = el % 2
            if start > 0 and end > 0:
                A11.append(i - le)
            elif not (start > 0 or end > 0):
                A00.append(i - le)
            else:
                A01 += 1
        prev = el

    start = 0
    for el in p:
        if el > 0:
            break
        start += 1
    if start == n:
        return 1

    end = 0
    for el in p[::-1]:
        if el > 0:
            break
        end += 1

    A00.sort(reverse=True)
    A11.sort(reverse=True)
    while A00:
        sect = A00.pop()
        if rest[0] < sect:
            A00.append(sect)
            break
        rest[0] -= sect

    while A11:
        sect = A11.pop()
        if rest[1] < sect:
            A11.append(sect)
            break
        rest[1] -= sect

    ans = A01
    ans += 2 * len(A00)
    ans += 2 * len(A11)

    prev = p[0]
    for el in p[1:]:
        if el > 0 and prev > 0 and (el + prev) % 2 > 0:
            ans += 1
        prev = el

    sOdd = p[start] % 2
    if rest[sOdd] < start:
        ans += 1
    else:
        rest[sOdd] -= start

    eOdd = p[-end-1] % 2
    if rest[eOdd] < end:
        ans += 1
    else:
        rest[eOdd] -= end

    return ans

