    @lru_cache(maxsize=None)
    def cost_to_transform(digit, target_digit):
        need_sticks = 0
        for stick_idx in range(7):
            if target_digit[stick_idx] == '0':
                if digit[stick_idx] == '0':
                    pass
                else:
                    return -1
            else:
                if digit[stick_idx] == '0':
                    need_sticks += 1
                else:
                    pass
        return need_sticks



    def can_transform_to(digit):
        psbl_num_costs = [] 
        for num in reversed(range(10)):
            target_digit = num_to_digit[num]
            cost = cost_to_transform(digit, target_digit)
            if cost == -1:
                continue
            psbl_num_costs.append((num, cost))
        return psbl_num_costs

    digit_transforms = [can_transform_to(digit) for digit in digits]
    min_cost_from = [0] * (n+1) 
    max_cost_from = [0] * (n+1) 
    for i in reversed(range(n)):

        min_cost = min(cost for num, cost in digit_transforms[i])
        max_cost = max(cost for num, cost in digit_transforms[i])
