        max_cost_from[i] = max_cost + max_cost_from[i+1]

    ans = [None] * n


    @lru_cache(maxsize=None)
    def max_nums(stick_cnt, from_digit_idx):
        if from_digit_idx == len(digits):
            if stick_cnt == 0:
                return True
            else:
                return None
        if not (min_cost_from[from_digit_idx] <= stick_cnt <= max_cost_from[from_digit_idx]):

            return None
        if stick_cnt < 0:
