        num_costs = digit_transforms[from_digit_idx]
        for num, cost in num_costs:

            max_nums_after = max_nums(stick_cnt - cost, from_digit_idx+1)
            if max_nums_after is None:
                continue
            ans[from_digit_idx] = num
            return True

