    def KMP(S, word):
        def partial_match_table(word):
            table = [0] * (len(word) + 1)
            table[0] = -1
            i, j = 0, 1

            while j < len(word):
                matched = word[i] == word[j]

                if not matched and i > 0:
                    i = table[i]
                else:
                    if matched:
                        i += 1
                    j += 1
                    table[j] = i

            return table

        table = partial_match_table(word)

        i, p = 0, 0
        match = []
        while (i < len(S) and p < len(word)):

            if S[i] == word[p]:
                i += 1;
                p += 1
                if p == len(word):
                    match.append(i - p)
                    p = table[p]
            else:
                if p == 0:
                    i += 1
                else:
                    p = table[p]

        return match

    class UnionFind():
        def __init__(self, n):
            self.parent = [-1 for _ in range(n)]


        def reset(self):
            self.parent = [-1] * len(self.parent)

        def find(self, x):

            if self.parent[x] < 0:
                return x
            else:
                self.parent[x] = self.find(self.parent[x])
                return self.parent[x]

        def unite(self, x, y):

            x, y = self.find(x), self.find(y)
            if x == y:
                return False
            else:
                if self.size(x) < self.size(y):
                    x, y = y, x
                self.parent[x] += self.parent[y]
                self.parent[y] = x

        def same(self, x, y):

            return self.find(x) == self.find(y)

        def size(self, x):

            x = self.find(x)
            return -self.parent[x]

        def is_root(self, x):

            return self.parent[x] < 0

        def roots(self):

            return [i for i, x in enumerate(self.parent) if x < 0]

        def members(self, x):

            root = self.find(x)
            return [i for i in range(self.n) if self.find(i) == root]

        def group_count(self):

            return len(self.roots())

        def all_group_members(self):

            return {r: self.members(r) for r in self.roots()}

