def go():
    n = int(input())
    e = {i: set() for i in range(n)}
    for i in range(n - 1):
        a, b = map(lambda s: int(s) - 1, input().split())
        e[a].add(b)
        e[b].add(a)

    parent = [-1 for v in range(n)]
    lev = [-1 for v in range(n)]







    stack = [0]
    lev[0]=0
    parent[0]=0
    while stack:
        v = stack.pop()
        for u in e[v]:
            if parent[u] == -1:
                lev[u] = lev[v]+1
                parent[u] = v
                stack.append(u)




    levmx = max(lev)
    bindep = levmx.bit_length()
    P = [[-1] * bindep for _ in range(n)]

    for i in range(n):
        P[i][0] = parent[i]

    for j in range(1, bindep):
        for i in range(n):
            if P[i][j - 1] != -1:
                P[i][j] = P[P[i][j - 1]][j - 1]


    def lca(u, v):
        if lev[u] < lev[v]:
            u, v = v, u

        dist = lev[u] - lev[v]
        while dist:
            podn = dist.bit_length() - 1
            u = P[u][podn]
            dist -= (1 << podn)

        if u == v:
            return u

        j = bindep - 1
        while j >= 0:
            if (P[u][j] != -1) and (P[u][j] != P[v][j]):
                u = P[u][j]
                v = P[v][j]
            j -= 1

        return parent[u]


    def dist(a, b):
        return lev[a] + lev[b] - 2 * lev[lca(a, b)]

    ans=[]
    Q = int(input())
    for _ in range(Q):
        x, y, a, b, k = map(int, input().split())
        x, y, a, b = map(lambda aa: aa - 1, [x, y, a, b])
        dab = dist(a, b)
        if dab <= k and (dab - k) % 2 == 0:
            ans.append('YES')
        else:

            dax = dist(a, x)
            dby = dist(b, y)
            if dax + 1 + dby <= k and \
                    (k- (dax + 1 + dby))%2==0:
                ans.append ('YES')
            else:
                day = dist(a, y)
                dbx = dist(b, x)
                if dbx + 1 + day <= k and \
                    (k- (dbx + 1 + day))%2==0:
                    ans.append ('YES')
                else:
                    ans.append('NO')
    print('\n'.join(ans))

def main():
    N = 400005
    MOD = 10 ** 9 + 7
    fact = [1] + [i+1 for i in range(N)]
    for i in range(1, N + 1):
        fact[i] *= fact[i - 1]
        fact[i] %= MOD

    def inv(n): return pow(n, MOD - 2, MOD)

    def simplex(n, k): 
        if n == 0: return 1
        if k == 0: return 0
        return fact[n + k - 1] * inv(fact[n]) * inv(fact[k - 1]) % MOD

    def F1(z, i):
        if z == 1:
            return 1
        if z % 4 == 2:
            x = z // 4 * 2
            j = i % 4
            if j == 0:
                return simplex(x, i // 4 * 2 + 1)
            elif j == 1:
                return simplex(x, i // 4 * 2 + 1) * 2 % MOD
            elif j == 2:
                return MOD - simplex(x, i // 4 * 2 + 2)
            else:
                return 0
        elif z % 4 == 0:
            if i == 0:
                return MOD - 1
            if i == 1:
                return 0
            i -= 2
            x = z // 4 * 2 - 1
            j = i % 4
            if j == 0:
                return simplex(x, i // 4 * 2 + 2)
            elif j == 1:
                return simplex(x, i // 4 * 2 + 2) * 2 % MOD
            elif j == 2:
                return MOD - simplex(x, i // 4 * 2 + 3)
            else:
                return 0
        elif z % 4 == 3:
            if i == 0:
                return MOD - 1
            i -= 1
            x = z // 4 * 2 + 1
            y = z // 4 * 2 - 1
            j = i % 4
            if j % 4 == 0:
                return simplex(x, i // 4 * 2 + 1)
            elif j % 4 == 1 or j % 4 == 2:
                return simplex(x, i // 4 * 2 + 2)
            else:
                z1 = 0 if y < 0 else simplex(y, i // 4 * 2 + 3)
                ans = simplex(x, i // 4 * 2 + 1) - z1
                if ans < 0: ans += MOD
                return ans
        else:
            if i < 2:
                return 1
            if i == 2:
                return MOD - (z // 4 * 2 - 1)
            i -= 3
            x = z // 4 * 2
            y = z // 4 * 2 - 2
            j = i % 4
            if j % 4 == 0:
                return simplex(x, i // 4 * 2 + 2)
            elif j % 4 == 1 or j % 4 == 2:
                return simplex(x, i // 4 * 2 + 3)
            else:
                z1 = 0 if y < 0 else simplex(y, i // 4 * 2 + 4)
                ans = simplex(x, i // 4 * 2 + 2) - z1
                if ans < 0: ans += MOD
                return ans

    def F2(n): 
        if n == 1: return [1]
        return [F1(i, n - i) for i in range(1, n + 1)]


    n = int(stdin.readline())
    a = [int(x) for x in stdin.readline().split()]
    coeffs = F2(n)
    ans = 0
    for c, x in zip(coeffs, a):
        ans += c * x % MOD
        if ans >= MOD:
            ans -= MOD
    stdout.write('{}\n'.format(ans))

