def process(A, B, Q):
    S = [0]
    n = len(A)
    for i in range(n):
        ai = A[i]
        bi = B[i]
        di = bi-ai
        S.append(S[-1]+di)
    n = len(S)
    p = math.log(n)/math.log(2)
    p = math.ceil(p)
    p = 2**p
    min_tree = [None for i in range(2*p-1)]
    max_tree = [None for i in range(2*p-1)]
    for i in range(p):
        if i < n:
            min_tree[i] = S[i]
            max_tree[i] = S[i]
        else:
            min_tree[i] = float('inf')
            max_tree[i] = -1*float('inf')
    for i in range(p, 2*p-1):
        i1 = (2*p-2)-i
        j1 = 2*i1+1
        j2 = 2*i1+2
        i_left = (2*p-2)-j1
        i_right = (2*p-2)-j2
        min_tree[i] = min(min_tree[i_left], min_tree[i_right])
        max_tree[i] = max(max_tree[i_left], max_tree[i_right])
    def find_max(l, r, start_l = 0, start_r = p-1, start_i = 2*p-2):
        if start_i < 0:
            return
        if l==r:
            return max_tree[l]
        if l==start_l and r==start_r:
            return max_tree[start_i]
        i1 = (2*p-2)-start_i
        i_l = (2*p-2)-(2*i1+2)
        i_r = (2*p-2)-(2*i1+1)
        m1 = (start_l+start_r)//2
        if l > m1:
            return find_max(l, r, start_l=m1+1, start_r=start_r, start_i=i_r)
        elif r <= m1:
            return find_max(l, r, start_l=start_l, start_r=m1, start_i=i_l)
        else:
            max1 = find_max(l, m1, start_l=start_l, start_r=m1, start_i=i_l)
            max2 = find_max(m1+1, r, start_l=m1+1, start_r=start_r, start_i=i_r)
            return max(max1, max2)
    def find_min(l, r, start_l = 0, start_r = p-1, start_i = 2*p-2):
        assert start_l <= l <= r <= start_r
        if start_i < 0:
            return
        if l==r:
            return min_tree[l]
        if l==start_l and r==start_r:
            return min_tree[start_i]
        i1 = (2*p-2)-start_i
        i_l = (2*p-2)-(2*i1+2)
        i_r = (2*p-2)-(2*i1+1)
        m1 = (start_l+start_r)//2
        if l > m1:
            return find_min(l, r, start_l=m1+1, start_r=start_r, start_i=i_r)
        elif r <= m1:
            return find_min(l, r, start_l=start_l, start_r=m1, start_i=i_l)
        else:
            min1 = find_min(l, m1, start_l=start_l, start_r=m1, start_i=i_l)
            min2 = find_min(m1+1, r, start_l=m1+1, start_r=start_r, start_i=i_r)
            return min(min1, min2)
    answer = []
    for l, r in Q:
        s1 = S[l-1]
        s2 = S[r]
        if s1 != s2:
            answer.append(-1)
        else:
            my_min = find_min(l, r)
            my_max = find_max(l, r)
            if my_min-s1 < 0:
                answer.append(-1)
            else:
                answer.append(my_max-s1)
    return answer

