                endodd=end
        end=i
        prev=start

        for i in range(start+1,end+1):
            if a[i]==0:
                continue
            if i-prev>1:
                if a[i]%2==0 and a[prev]%2==0:
                    es.append(i-prev-1)
                elif a[i]%2!=0 and a[prev]%2!=0:
