        adj[a].append(b)
        adj[b].append(a)

    et, depth = EulerTour(adj, 1)
    depth_list = [0] * len(et)
    left = [-1] * (N + 1)
    right = [-1] * (N + 1)
    for i, v in enumerate(et):
        depth_list[i] = depth[v]
        if left[v] < 0:
            left[v] = i
        right[v] = i
    ST = SparseTable(depth_list)

    for _ in range(M):
        v_list = list(map(int, input().split()))
        vd = [(v, depth[v]) for v in v_list[1:]]
        vd.sort(key=lambda x: x[1])
        ok = 1
        L = len(vd)
        for i in range(L-1):
